<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --taskbar-bg: #2d2d2d;
            --window-bg: #303030;
            --text-color: #e0e0e0;
            --accent-color: #5c9eff; /* Ubuntu blue-ish */
            --close-btn-color: #ff4d4d;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html { margin: 0; padding: 0; height: 100%; width: 100%; overflow: hidden; font-family: 'Ubuntu', 'Segoe UI', sans-serif; background-color: var(--bg-color); color: var(--text-color); }

        /* Desktop Area */
        #desktop {
            width: 100vw;
            height: calc(100vh - 48px); /* Minus taskbar height */
            position: relative;
            background: linear-gradient(135deg, #2b32b2 0%, #1488cc 100%); /* Simple wallpaper */
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            height: 48px;
            background-color: var(--taskbar-bg);
            display: flex;
            align-items: center;
            padding: 0 10px;
            box-shadow: 0 -2px 5px rgba(0,0,0,0.3);
            z-index: 1000;
        }

        /* Launchers */
        .launcher {
            width: 48px;
            height: 48px;
            margin-right: 8px;
            border-radius: 8px;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            transition: background 0.2s;
        }
        .launcher:hover { background-color: #444; }
        .launcher.active { background-color: #555; border-bottom: 3px solid var(--accent-color); }

        /* Icons (CSS Shapes) */
        .icon-files { color: #e0ac19; font-size: 24px; }
        .icon-notepad { color: #ff8c00; font-size: 24px; }

        /* Windows */
        .window {
            position: absolute;
            background-color: var(--window-bg);
            border-radius: 6px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none; /* Hidden by default */
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            overflow: hidden;
            border: 1px solid #444;
        }

        .window-header {
            height: 32px;
            background-color: #3c3c3c;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            cursor: default;
        }

        .window-title { font-size: 14px; font-weight: bold; }

        .win-close {
            width: 24px;
            height: 24px;
            border-radius: 50%;
            background-color: #555;
            color: #aaa;
            display: flex;
            justify-content: center;
            align-items: center;
            cursor: pointer;
            font-size: 16px;
        }
        .win-close:hover { background-color: var(--close-btn-color); color: white; }

        /* Files App Specifics */
        #files-window { top: 50px; left: 50px; width: 600px; height: 400px; }

        .file-toolbar {
            padding: 8px;
            background-color: #2d2d2d;
            border-bottom: 1px solid #444;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        #files-path { font-family: monospace; color: #aaa; font-size: 13px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 200px;}

        .fs-list {
            flex-grow: 1;
            padding: 10px;
            overflow-y: auto;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 5px;
        }

        .fs-item {
            background-color: #404040;
            padding: 10px 5px;
            text-align: center;
            border-radius: 4px;
            cursor: pointer;
            font-size: 13px;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 60px;
        }
        .fs-item:hover { background-color: #505050; }
        .fs-item.folder { color: #4da6ff; }
        .fs-item.file { color: #aaffaa; }

        /* Notepad App Specifics */
        #notepad-window { top: 80px; left: 100px; width: 500px; height: 350px; }

        .tabs-container {
            background-color: #2d2d2d;
            display: flex;
            align-items: center;
            padding-left: 5px;
            border-bottom: 1px solid #444;
            height: 30px;
        }

        .tab {
            background-color: #3c3c3c;
            padding: 4px 12px;
            margin-right: 2px;
            border-radius: 4px 4px 0 0;
            font-size: 13px;
            cursor: pointer;
            max-width: 150px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            border: 1px solid transparent;
        }
        .tab.active { background-color: var(--window-bg); font-weight: bold; }

        #new-tab {
            margin-left: auto;
            background: none;
            border: none;
            color: #aaa;
            cursor: pointer;
            padding: 4px 8px;
            font-size: 12px;
        }
        #new-tab:hover { color: white; text-decoration: underline; }

        #editor {
            flex-grow: 1;
            background-color: #303030;
            color: #ddd;
            border: none;
            resize: none;
            padding: 8px;
            font-family: 'Ubuntu Mono', monospace;
            font-size: 14px;
            outline: none;
        }

    </style>
</head>
<body>

<div id="desktop">

    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="window-header">
            <span class="window-title">Files</span>
            <div class="win-close" onclick="toggleWindow('files-window')">✕</div>
        </div>
        <div class="file-toolbar">
            <button id="files-up" style="padding: 4px 8px; background:#444; border:none; color:white; cursor:pointer;">↑ Up</button>
            <span id="files-path">/</span>
        </div>
        <div id="fs-list" class="fs-list">
            <!-- Files injected here -->
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="window-header">
            <span class="window-title">Text Editor</span>
            <div class="win-close" onclick="toggleWindow('notepad-window')">✕</div>
        </div>
        <div class="tabs-container" id="tabs">
            <!-- Tabs injected here -->
        </div>
        <button id="new-tab">+ New Tab</button>
        <textarea id="editor" placeholder="Type here..."></textarea>
    </div>

</div>

<div id="taskbar">
    <div class="launcher icon-files" id="open-files" onclick="toggleWindow('files-window')">
        <!-- Simple CSS Icon representation -->
        <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M20 6h-8l-2-2H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2zm0 12H4V8h16v10z"/></svg>
    </div>
    <div class="launcher icon-notepad" id="open-notepad" onclick="toggleWindow('notepad-window')">
        <!-- Simple CSS Icon representation -->
        <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>
    </div>
</div>

<script>
    /* --- File System Data Structure --- */
    const fileSystem = {
        '/': [
            { name: 'bin', type: 'folder' },
            { name: 'etc', type: 'folder' },
            { name: 'home', type: 'folder' },
            { name: 'usr', type: 'folder' },
            { name: 'var', type: 'folder' }
        ],
        '/bin': [
            { name: 'bash', type: 'file' },
            { name: 'ls', type: 'file' },
            { name: 'cp', type: 'file' }
        ],
        '/etc': [
            { name: 'passwd', type: 'file' },
            { name: 'hosts', type: 'file' }
        ],
        '/home': [
            { name: 'user', type: 'folder' }
        ],
        '/usr': [
            { name: 'bin', type: 'folder' },
            { name: 'lib', type: 'folder' },
            { name: 'share', type: 'folder' }
        ],
        '/var': [
            { name: 'log', type: 'folder' },
            { name: 'cache', type: 'folder' }
        ],
        '/home/user': [
            { name: 'Documents', type: 'folder' },
            { name: 'Downloads', type: 'folder' },
            { name: 'Pictures', type: 'folder' },
            { name: 'readme.txt', type: 'file' }
        ],
        '/home/user/Documents': [
            { name: 'project_notes.md', type: 'file' },
            { name: 'todo.txt', type: 'file' }
        ],
        '/home/user/Downloads': [
            { name: 'image.png', type: 'file' },
            { name: 'setup.exe', type: 'file' }
        ],
        '/home/user/Pictures': [
            { name: 'vacation.jpg', type: 'file' }
        ]
    };

    /* --- State Management --- */
    let currentPath = ['/'];

    // Notepad Data Structure
    let notepadData = []; 
    const STORAGE_KEY = 'ubuntu_notepad_data';

    /* --- Initialization --- */
    window.onload = function() {
        renderFiles();
        loadNotepad();

        // Event Listeners
        document.getElementById('files-up').addEventListener('click', goUp);
        document.getElementById('new-tab').addEventListener('click', createNewTab);

        // Double click handling for files
        const fsList = document.getElementById('fs-list');
        fsList.addEventListener('dblclick', (e) => {
            if(e.target.classList.contains('fs-item')) {
                const item = e.target;
                const name = item.innerText;

                // Check if it's a folder or file based on data structure logic
                // We need to find the index in currentPath to know what we clicked
                // Simplified: check class. If folder, navigate. If file, alert.
                // To do this properly, we pass context.
            }
        });
    };

    /* --- Files App Logic --- */

    function renderFiles() {
        const list = document.getElementById('fs-list');
        list.innerHTML = '';

        if (currentPath.length === 0) return; // Root handled separately usually, but here we handle root as empty array in object? No, root is key '/'.

        let currentDirName = currentPath[currentPath.length - 1];
        let parentPathStr = currentPath.slice(0, -1).join('/');

        // Get children from data structure
        let children = [];
        if (parentPathStr === '/') {
            children = fileSystem['/'];
        } else {
            children = fileSystem[parentPathStr];
        }

        document.getElementById('files-path').innerText = currentDirName;

        children.forEach(item => {
            const div = document.createElement('div');
            div.className = `fs-item ${item.type}`;
            div.innerText = item.name;

            // Double click logic: 
            // We need to know if it's a folder. 
            // If folder, push to path and re-render.
            div.addEventListener('dblclick', () => {
                if (item.type === 'folder') {
                    currentPath.push(item.name);
                    renderFiles();
                } else {
                    alert(`Opening file: ${item.name}`);
                }
            });

            list.appendChild(div);
        });
    }

    function goUp() {
        if (currentPath.length > 1) {
            currentPath.pop();
            renderFiles();
        }
    }

    /* --- Window Management --- */

    function toggleWindow(id) {
        const win = document.getElementById(id);
        if (win.style.display === 'none') {
            win.style.display = 'flex';
            // Bring to front logic could go here, but simple display is enough for this spec.
        } else {
            win.style.display = 'none';
        }
    }

    /* --- Notepad App Logic --- */

    function loadNotepad() {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
            notepadData = JSON.parse(stored);
        } else {
            // Default state: one empty tab
            notepadData.push({ id: 'tab-1', title: 'Untitled-1', content: '' });
        }

        renderNotepad();
    }

    function saveNotepad() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadData));
    }

    function createNewTab() {
        const id = 'tab-' + Date.now();
        notepadData.push({ id: id, title: 'Untitled', content: '' });
        renderNotepad();
    }

    function switchTab(tabId) {
        // Update UI classes
        document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));

        const activeTab = notepadData.find(t => t.id === tabId);
        if (activeTab) {
            // Find the tab element to activate it
            const tabsContainer = document.getElementById('tabs');
            const tabElements = Array.from(tabsContainer.children);

            // Filter out the "New Tab" button which is not a .tab
            const realTabs = tabElements.filter(el => el.classList.contains('tab'));

            const activeEl = realTabs.find(el => el.innerText === activeTab.title);
            if(activeEl) activeEl.classList.add('active');

            // Update textarea
            document.getElementById('editor').value = activeTab.content;
        }
    }

    function renderNotepad() {
        const tabsContainer = document.getElementById('tabs');
        const editor = document.getElementById('editor');

        // Clear existing tabs (keep the button)
        const newBtn = document.getElementById('new-tab');
        tabsContainer.innerHTML = '';
        tabsContainer.appendChild(newBtn);

        notepadData.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = 'tab';
            tabEl.innerText = tab.title;

            // If it's the first tab, make it active initially
            if (notepadData.length === 1) tabEl.classList.add('active');

            tabEl.addEventListener('click', () => switchTab(tab.id));
            tabsContainer.appendChild(tabEl);
        });

        // Ensure editor reflects current state
        const activeTab = notepadData.find(t => t.id === (document.querySelector('.tab.active') ? document.querySelector('.tab.active').innerText : ''));
        if(activeTab) {
             // Find the ID of the active tab element to get its object
             // Actually simpler: just sync editor with the first tab or find by title match? 
             // Let's rely on the fact that we render tabs. The first one is usually active unless clicked.
             // But wait, if I reload, I need to know which one was active.
             // For simplicity in this spec, let's just sync with the first tab or handle via ID mapping.
        }

        // Better approach: Sync editor immediately after render based on active class
        const activeEl = document.querySelector('.tab.active');
        if(activeEl) {
            const activeTabObj = notepadData.find(t => t.title === activeEl.innerText);
            if(activeTabObj) editor.value = activeTabObj.content;
        }
    }

    // Editor Input Listener to save content to data model
    document.getElementById('editor').addEventListener('input', (e) => {
        const activeEl = document.querySelector('.tab.active');
        if (activeEl) {
            const title = activeEl.innerText;
            const tabObj = notepadData.find(t => t.title === title);
            if (tabObj) {
                tabObj.content = e.target.value;
                saveNotepad();
            }
        }
    });

</script>

</body>
</html>
